head.script:
scwin.isDelete = "";
scwin.isUpdate = "";
scwin.spplyAmt = 0;
scwin.vatAmt = 0;
scwin.spplyAmtFcrc = 0;
scwin.bilgAmt = 0;
scwin.bilgAmtFcrc = 0;
scwin.fcrcBilgAmt = 0;
scwin.clntMgntYn = 0; // 관리거래처 체크

scwin.onpageload = function () {
    scwin.isDelete = false;
    scwin.isUpdate = false;

    var arrParent = $p.getAllParameter().paramData;
    var sellingEvidence = arrParent.sellingEvidence;
    var commonList = arrParent.commonList;

    ds_sellingEvidence.removeAll();
    ds_sellingEvidence.setRowJSON(0, sellingEvidence);
    ds_commonList.setJSON(commonList);

    if (ds_sellingEvidence.getCellData(0, "slipNo") != null && ds_sellingEvidence.getCellData(0, "slipNo") != "") {
        scwin.f_displayGridColumn(gr_commonList, ["choice"], "Show", false); 

        var cnt = ds_commonList.getRowCount();
        for (var i = cnt - 1; i >= 0; i--) {
            if (ds_commonList.getCellData(i, "choice") != "T") {
                ds_commonList.removeRow(i);
            }
        }
        $c.gus.cfDisableBtn([btn_save]);
    } else {
        $c.gus.cfDisableBtn([btn_delete]);
    }

    $c.gus.cfEnableObj(ica_slipCloseYm, false);
    $c.gus.cfEnableObj(ica_taxCloseYm, false);
    $c.gus.cfEnableObj(ed_collMoneyAcctDeptCd, false);

    scwin.f_pushSellingEvidence();

    if (ds_commonList.getRowCount() > 0) {
        total.setValue(ds_commonList.getRowCount());
    }
};

scwin.onUdcCompleted = function () {
    // 할인할증집계여부 체크박스 초기화
    cbx_sumCheck.setValue("Y")
};

scwin.ondataload = function () {

};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
scwin.f_displayGridColumn = function (gridObj, colIdArr, mode, status) {
    for (var i = 0; i < colIdArr.length; i++) {
        var colId = colIdArr[i];
        var colIdx = gridObj.getColumnIndex(colId);

        if (colIdx == -1) continue;

        if (mode == "Show") {
            var isVisible = (String(status) === "true");
            gridObj.setColumnVisible(colIdx, isVisible);
        }
    }
};

scwin.f_OnUnload = function () {
    var returnObject = new Object();
    if (scwin.isDelete) {
        returnObject.flag = "DELETE";
        returnObject.curRow = ds_sellingEvidence.getCellData(0, "curRow");
    } else if (scwin.isUpdate) {
        returnObject.flag = "UPDATE";
        returnObject.curRow = ds_sellingEvidence.getCellData(0, "curRow");
        returnObject.sellVatNo = ds_sellingEvidence.getCellData(0, "sellVatNo");
        returnObject.slipNo = ds_sellingEvidence.getCellData(0, "slipNo");
        returnObject.dcsnClsNm = ds_sellingEvidence.getCellData(0, "dcsnClsNm");
        returnObject.spplyDt = ds_sellingEvidence.getCellData(0, "spplyDt");
        returnObject.slipDt = ds_sellingEvidence.getCellData(0, "slipDt");
        returnObject.summary = ds_sellingEvidence.getCellData(0, "summary");
        returnObject.goods = ds_sellingEvidence.getCellData(0, "goods");
        returnObject.collMoneyAcctDeptCd = ds_sellingEvidence.getCellData(0, "collMoneyAcctDeptCd");
        returnObject.collMoneyAcctDeptNm = ds_sellingEvidence.getCellData(0, "collMoneyAcctDeptNm");
    } else {
        returnObject.flag = "";
        returnObject.curRow = ds_sellingEvidence.getCellData(0, "curRow");
        returnObject.spplyDt = ica_spplyDt.getValue();
        returnObject.slipDt = ica_slipDt.getValue();
        returnObject.summary = ed_summary.getValue();
        returnObject.goods = ed_goods.getValue();
        returnObject.collMoneyAcctDeptCd = ed_collMoneyAcctDeptCd.getValue();
        returnObject.collMoneyAcctDeptNm = ed_collMoneyAcctDeptNm.getValue();
    }

    $c.win.closePopup(returnObject);  
};

// 매출증빙 화면 세팅
scwin.f_pushSellingEvidence = function () {
    ed_sellVatNo.setValue(ds_sellingEvidence.getCellData(0, "sellVatNo"));
    ica_spplyDt.setValue(ds_sellingEvidence.getCellData(0, "spplyDt"));
    ed_crn.setValue(ds_sellingEvidence.getCellData(0, "crn"));		
    ed_busiNm.setValue(ds_sellingEvidence.getCellData(0, "busiNm"));
    ed_repstNm.setValue(ds_sellingEvidence.getCellData(0, "repstNm"));
    ed_bilgLodeptCd.setValue(ds_sellingEvidence.getCellData(0, "bilgLodeptCd"));
    ed_bilgLobranNm.setValue(ds_sellingEvidence.getCellData(0, "bilgLobranNm"));
    ed_slipNo.setValue(ds_sellingEvidence.getCellData(0, "slipNo"));
    ica_slipDt.setValue(ds_sellingEvidence.getCellData(0, "slipDt"));
    ed_taxnClsNm.setValue(ds_sellingEvidence.getCellData(0, "taxnClsNm"));
    ed_summary.setValue(ds_sellingEvidence.getCellData(0, "summary"));
    ed_goods.setValue(ds_sellingEvidence.getCellData(0, "goods"));
    ed_spplyAmt.setValue(ds_sellingEvidence.getCellData(0, "spplyAmt"));
    ed_vatAmt.setValue(ds_sellingEvidence.getCellData(0, "vatAmt"));
    ed_sumAmt.setValue(ds_sellingEvidence.getCellData(0, "sumAmt"));
    ed_spplyAmtFcrc.setValue(ds_sellingEvidence.getCellData(0, "spplyAmtFcrc"));
    ed_collMoneyAcctDeptCd.setValue(ds_sellingEvidence.getCellData(0, "collMoneyAcctDeptCd"));
    ed_collMoneyAcctDeptNm.setValue(ds_sellingEvidence.getCellData(0, "collMoneyAcctDeptNm"));
    ed_bilgClntNo.setValue(ds_sellingEvidence.getCellData(0, "bilgClntNo"));
    ed_bilgClntNm.setValue(ds_sellingEvidence.getCellData(0, "bilgClntNm"));

    ica_slipCloseYm.setValue(ds_sellingEvidence.getCellData(0, "slipCloseYm"));
    ica_taxCloseYm.setValue(ds_sellingEvidence.getCellData(0, "taxCloseYm"));
};

// 관리 거래처 체크 
scwin.f_retrieveCtrtNo2 = async function (bilgClntNo) {
    if (ds_cndCtrtNo.getRowCount() > 0)
        ds_cndCtrtNo.removeAll();	

    // 검색조건값 세팅
    var rowIndex = ds_cndCtrtNo.insertRow();	
    ds_cndCtrtNo.setCellData(rowIndex, "ctrtClntNo", bilgClntNo);	// 거래처 코드 

    // 조회
    let e = await $c.sbm.execute(sbm_retrieveCtrtNo2);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_retrieveCtrtNo2_submitdone(e);
    }
};

// 저장
scwin.f_Save = async function () {
    // 세금계산서거 발행되었으면....
    if (ds_sellingEvidence.getCellData(0, "slipNo") != null && ds_sellingEvidence.getCellData(0, "slipNo") != ""){
        await $c.gus.cfAlertMsg("매출증빙 내역이 있는 자료는 저장 할 수 없습니다.");
        return;
    }

    // 청구일  경우 매출입구분이 영수매출인 경우는 세금계산서 생성 불가 2011.06.22
    if (ds_sellingEvidence.getCellData(0, "receiveSellingYn") == "1") {
        await $c.gus.cfAlertMsg("청구할 수 없는  영수매출 거래처입니다.\n다시 확인하십시오!");
        return;
    }

    if ($c.gus.cfIsNull(ed_collMoneyAcctDeptCd.getValue())) {
        await $c.gus.cfAlertMsg("수금부서는 필수 입력 항목입니다. \r\r [/공통/거래처/거래처관리] 화면에서 수금부서를 먼저 등록하세요.."); //@은(는) 필수 입력 항목입니다
        return;
    }

    // validation check     
    if (!await $c.gus.cfValidate([ica_spplyDt, ica_slipDt, ed_summary, ed_goods, ed_collMoneyAcctDeptCd])) {
        return;
    }

    // 청구 / 영수가 청구일 경우에만 관리거래처 체크

    await scwin.f_retrieveCtrtNo2(ds_sellingEvidence.getCellData(0, "bilgClntNo"));

    if (scwin.clntMgntYn == 1) {
        await $c.gus.cfAlertMsg("청구처(" + ds_sellingEvidence.getCellData(0, "bilgClntNo") + ") 업체가  관리대상 거래처 입니다.\n거래처코드의 상태를 확인하시고, 관리거래처인 경우에는 저장할 수 없습니다.");
        return;
    }

    $c.gus.cfCopyDataSetHeader(ds_commonList, ds_commonRetriveList);
    var	transRow;
    var chkCnt = 0;

    for (var i = 0; i < ds_commonList.getRowCount(); i++) { 
        if (ds_commonList.getCellData(i, "choice") == "T") {
            // transRow = ds_commonList.ExportData(i, 1, false);
            // ds_commonRetriveList.ImportData(transRow);
            // chkCnt++;

            transRow = ds_commonList.getRowData(i);
            var newRowIndex = ds_commonRetriveList.insertRow();
            ds_commonRetriveList.setRowData(newRowIndex, transRow);      
            chkCnt++;
        }
    }

    if (chkCnt < 1){  
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["저장할 거래명세서"]);
        return;
    }

    if (! await $c.win.confirm(MSG_CM_CRM_001))
        return;

    ds_sellingEvidence.setCellData(0, "spplyAmt", ed_spplyAmt.getValue());
    ds_sellingEvidence.setCellData(0, "spplyAmtFcrc", ed_spplyAmtFcrc.getValue());
    ds_sellingEvidence.setCellData(0, "vatAmt", ed_vatAmt.getValue());
    ds_sellingEvidence.setCellData(0, "sumAmt", ed_sumAmt.getValue());
    ds_sellingEvidence.setCellData(0, "spplyDt", ica_spplyDt.getValue());
    ds_sellingEvidence.setCellData(0, "slipDt", ica_slipDt.getValue());
    ds_sellingEvidence.setCellData(0, "summary", ed_summary.getValue());
    ds_sellingEvidence.setCellData(0, "goods", ed_goods.getValue());
    ds_sellingEvidence.setCellData(0, "collMoneyAcctDeptCd", ed_collMoneyAcctDeptCd.getValue());
    ds_sellingEvidence.setCellData(0, "certiCnt", chkCnt);

  //  scwin.dataSetInfo(ds_sellingEvidence, true);
  //  scwin.dataSetInfo(ds_commonRetriveList, true);

    let e = await $c.sbm.execute(sbm_createTaxInvoice);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_createTaxInvoice_submitdone(e);
    }
};

// 삭제
scwin.f_Delete = async function () {
    // 세금계산서거 발행되었으면....
    if (ds_sellingEvidence.getCellData(0, "slipNo") == null || ds_sellingEvidence.getCellData(0, "slipNo") == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["삭제할 셀금계산서"]);
        return;
    }

    if (!await $c.win.confirm(MSG_CM_CRM_004))
        return;

    if (!await scwin.f_CheckTaxCancelSpplyDt())
        return;

    ds_sellingEvidence.setCellData(0, "cancelSpplyDt", ica_cancelSpplyDt.getValue());

    let e = await $c.sbm.execute(sbm_deleteTaxInvoice);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_deleteTaxInvoice_submitdone(e);
    }
};

// 세금계산서 취소 때  세무마감여부 CHECK
scwin.f_CheckTaxCancelSpplyDt = async function () {
    var taxCloseYm  = ica_taxCloseYm.getValue();
    var spplyYm		= ica_spplyDt.getValue().substring(0, 6);
    var isTrue;

    if (taxCloseYm >= spplyYm ) {
        isTrue = await $c.win.confirm("세무마감된 계산서를 취소할 경우에는 반드시 거래처에 수정세금계산서를 발행해야 합니다.(거래처와 합의 요함)\n\n세금계산서 및 전표를 취소하시겠습니까?");
        if (!isTrue) return;

        if ($c.gus.cfIsNull(ica_cancelSpplyDt.getValue())) { 
            if (await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["[수정세금계산서 공급일자 ]"])) { //@은(는) 필수 입력 항목입니다
                ica_cancelSpplyDt.focus();
                return false;
            } 
        }

        if(!await $c.gus.cfValidate([ed_cancelSpplyDt])) {
            ica_cancelSpplyDt.focus();
            return;
        }
    }
    return true;
};


// PopUp
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면 
    switch (disGubun) {
        case 1: // 수금부서 PopUp 호출
            udc_comPopup.setSelectId("retrieveAcctDeptCdInfo");
            rtnList = await udc_comPopup.cfCommonPopUpAsync('', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            cfSetReturnValue(rtnList, ed_collMoneyAcctDeptCd, ed_collMoneyAcctDeptNm);  // 수금부서코드, 수금부서명
        break;
        case 2: // 이메일등록
            // var where = "";
            // var check = "F";
            // udc_comPopup.setSelectId("retrieveClntEmail");
            // rtnList = await udc_comPopup.cfCommonPopUpAsync('', ed_bilgClntNo.getValue().trim(), ed_email.getValue().trim(), check, null, null, null, null, where, null, null, null, null); 

            // if (rtnList != null ) {
            //     if (rtnList[0] == "N/A") {
            //         return;
            //     }
            //     ed_email.setValue(rtnList[0]); // Email
            // } else {
            //     ed_email.setValue("");
            // }
        break;
        default:
        break;
    }
};

// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

// 엑셀 다운로드
scwin.f_downExcelSheet = async function () {
    if (await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
        $c.data.downloadGridViewExcel(gr_commonList, {"fileName": "거래명세서별 청구서 내역.xlsx", "sheetName": "거래명세서별 청구서 내역"});
    }
};

// 인쇄 (통합발행)
scwin.f_totalPrint = async function () {
    var param = "";
    var printCnt = 0;

    if(ds_sellingEvidence.getCellData(0, "sellVatNo") == null || ds_sellingEvidence.getCellData(0, "sellVatNo") == ""){
        await $c.gus.cfAlertMsg(MSG_CM_ERR_049,["발행할 통합발행내역"]);
        return;
    }

    if (!await $c.win.confirm("통합발행 하시겠습니까?")) {
        return;
    }

    for (var i = 0; i < ds_commonList.getRowCount(); i++) {
        var odi1 = "01";
        var odi2 = ds_commonList.getCellData(i, "inscrpFmlaPatternCd");

        const data = {
            reportName: "/ds/fs/fs_202_06_10_" + odi1 + "_" + odi2 + ".ozr",
            odiName : "fs_202_06_10_" + odi1 + "_" + odi2,
            odiParam: {
                bilgLodeptCd : ds_commonList.getCellData(i, "bilgLodeptCd"),
                bilgClntNo : ds_commonList.getCellData(i, "bilgClntNo"),
                qryConKnd : "02",
                confirmDtFm : "",
                confirmDtTo : "",
                spplyDtFm : "",
                spplyDtTo : "",
                modId : "",
                printFg : "",
                certiAggregateFg : "",
                dcsnClsCd : "",
                certiNo : ds_commonList.getCellData(i, "certiNo"),
                fmlaClsCd : ds_commonList.getCellData(i, "fmlaClsCd"),
                fmlaPatternCd : ds_commonList.getCellData(i, "fmlaPatternCd"),
                upperFmlaClsCd : "",
                upperFmlaPatternCd : "",
                sellVatNo : "",
                inscrpFmlaClsCd : ds_commonList.getCellData(i, "inscrpFmlaClsCd"),
                inscrpFmlaPatternCd : ds_commonList.getCellData(i, "inscrpFmlaPatternCd"),
                spplyFg : lc_spplyFg.getValue(),
                sumGbn : cbx_sumCheck.getValue() ? "Y" : "N",
            },
            viewerParam: {
                zoom: 100,
                mode : "silent",
                useprogressbar: false,
            },
            formParam: {}
        };

        await scwin.openPopup(data);
    }

    var spplyFg = "02p";
    if (lc_spplyFg.getValue() =="receive") {
        spplyFg = "02p";
    } else {
        spplyFg = "03p";
    }

    const data = {
        reportName: "/ac/fi/taxbiz/vatctrl/fi_401_01_"+spplyFg+".ozr",
        odiName : "fi_401_01_" + spplyFg,
        odiParam: {
            pchsSellCls : ds_sellingEvidence.getCellData(0, "sellVatNo"),
        },
        viewerParam: {
            zoom: 100,
            mode : "silent",
            useprogressbar: false,
        },
        formParam: {}
    };

    await scwin.openPopup(data);
};

scwin.openPopup = async function(data) {
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

scwin.gr_commonList_CustomFormatter = function(data, formattedData, rowIndex, colIndex) {
    let columnId =  $c.util.getComponent(this.id).getColumnID(colIndex);
    let val = data, color = "black";

    if (columnId == "vsslCdFrom") {
        var inscrpVsslCd = ds_commonList.getCellData(rowIndex, "inscrpVsslCd");
        var inscrpPortcnt = ds_commonList.getCellData(rowIndex, "inscrpPortcnt");
        if ($c.gus.cfIsNull(inscrpVsslCd) && $c.gus.cfIsNull(inscrpPortcnt)) {
            val = "";
        } else {
            val = inscrpVsslCd + "/" + inscrpPortcnt;
        }
    } 

    return val;
};

//-------------------------------------------------------------------------
// 공통팝업호출 callBack
//-------------------------------------------------------------------------
// 계약거래처

//-------------------------------------------------------------------------
// Sbm submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieveCtrtNo2_submitdone = async function (e) {
    var ctrtNoRows = ds_ctrtNo2.getRowCount();
    if (ctrtNoRows > 0) {
        // 계약번호가 서로 다른 것이 있는 경우, 선택을 default로 보여주기 위한 process
        var sameYn = "N";

        for (j = 0; j < ds_ctrtNo2.getRowCount(); j++) {
            if (1 == ds_ctrtNo2.getCellData(j, "mgntTrgtClntYn")) {
                sameYn = "Y";
                break;
            }
        }

        if (sameYn == "Y") {
            scwin.clntMgntYn = 1;
        } else {
            scwin.clntMgntYn = 0;
        }
    } else {
        await $c.gus.cfAlertMsg("거래처의 기본사항이 없습니다.");
    }
};

scwin.sbm_createTaxInvoice_submitdone = async function (e) {debugger;
    if (await $c.gus.cfAlertMsg(MSG_CM_INF_001)) {
        ds_sellingEvidenceResult.setJSON(e.responseJSON.OUT_DS1);
        if (ds_sellingEvidenceResult.getRowCount() > 0) {
            ds_sellingEvidence.setCellData(0, "sellVatNo", ds_sellingEvidenceResult.getCellData(0, "sellVatNo"));
            ds_sellingEvidence.setCellData(0, "slipNo", ds_sellingEvidenceResult.getCellData(0, "slipNo"));
            ds_sellingEvidence.setCellData(0, "dcsnClsNm", ds_sellingEvidenceResult.getCellData(0, "dcsnClsNm"));
            ds_sellingEvidence.setCellData(0, "spplyDt", ica_spplyDt.getValue());
            ds_sellingEvidence.setCellData(0, "slipDt", ica_slipDt.getValue());
            ds_sellingEvidence.setCellData(0, "summary", ed_summary.getValue());
            ds_sellingEvidence.setCellData(0, "goods", ed_goods.getValue());
            ds_sellingEvidence.setCellData(0, "collMoneyAcctDeptCd", ed_collMoneyAcctDeptCd.getValue());
            ds_sellingEvidence.setCellData(0, "collMoneyAcctDeptNm", ed_collMoneyAcctDeptNm.getValue());

            $c.gus.cfEnableBtnOnly([btn_delete]);
            scwin.f_pushSellingEvidence();
            gr_commonList.setColumnVisible("choice", false);
            scwin.isUpdate = true;
        }
    }
};


scwin.sbm_deleteTaxInvoice_submitdone = async function (e) {
    if (await $c.gus.cfAlertMsg(MSG_CM_INF_004)) {
        scwin.isDelete = true;
        var returnObject = new Object();
        returnObject.flag = "DELETE";
        returnObject.curRow = ds_sellingEvidence.getCellData(0, "curRow");
        $c.win.closePopup(returnObject);
    };
};

//-------------------------------------------------------------------------
// Event onClick
//-------------------------------------------------------------------------
// 닫기
scwin.btn_close_onclick = function (e) {
