//-------------------------------------------------------------------------
// DataSet 이벤트
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// 그리드 이벤트
//-------------------------------------------------------------------------
scwin.gr_commonList_onheaderclick = function (headerId) {
    var i = 0;
    if (headerId == "choice") {
        var bCheck= gr_commonList.getHeaderValue("choice");
        scwin.spplyAmt = 0;
        scwin.vatAmt = 0;
        scwin.spplyAmtFcrc = 0;
        scwin.bilgAmt = 0;
        scwin.bilgAmtFcrc = 0;
        scwin.fcrcBilgAmt = 0;
        if (bCheck == true) {
            for (i = 0; i < ds_commonList.getRowCount(); i++) {
                ds_commonList.setCellData(i, "choice", "T");
                scwin.spplyAmt = scwin.spplyAmt + Number(ds_commonList.getCellData(i, "spplyAmt"));
                scwin.vatAmt = scwin.vatAmt + Number(ds_commonList.getCellData(i, "vatAmt"));
                scwin.spplyAmtFcrc = scwin.spplyAmtFcrc + Number(ds_commonList.getCellData(i, "spplyAmtFcrc"));

                scwin.bilgAmt = scwin.bilgAmt + Number(ds_commonList.getCellData(i, "bilgAmt"));
                scwin.bilgAmtFcrc = scwin.bilgAmtFcrc + Number(ds_commonList.getCellData(i, "bilgAmtFcrc"));
                scwin.fcrcBilgAmt = scwin.fcrcBilgAmt + Number(ds_commonList.getCellData(i, "fcrcBilgAmt"));
            }
            ed_spplyAmt.setValue(scwin.spplyAmt);
            ed_vatAmt.setValue(scwin.vatAmt);
            ed_sumAmt.setValue(Number(scwin.spplyAmt) + Number(scwin.vatAmt));
            ed_spplyAmtFcrc.setValue(scwin.spplyAmtFcrc);
            ds_sellingEvidence.setCellData(0, "bilgAmtFcrc", scwin.bilgAmtFcrc);
            ds_sellingEvidence.setCellData(0, "fcrcBilgAmt", scwin.fcrcBilgAmt);
            ds_sellingEvidence.setCellData(0, "bilgAmt", scwin.bilgAmt);
        } else {
            for (i = 0; i < ds_commonList.getRowCount(); i++) {
                ds_commonList.setCellData(i, "choice", "F");
            }
            ed_spplyAmt.setValue(0);
            ed_vatAmt.setValue(0);
            ed_sumAmt.setValue(0);
            ed_spplyAmtFcrc.setValue(0);

            ds_sellingEvidence.setCellData(0, "bilgAmt", 0);
            ds_sellingEvidence.setCellData(0, "bilgAmtFcrc", 0);
            ds_sellingEvidence.setCellData(0, "fcrcBilgAmt", 0);
        }
    }
};

scwin.gr_commonList_oncellclick = function (rowIndex, columnIndex, columnId) {
    if (columnId == "choice") {
        scwin.spplyAmt = 0;
        scwin.vatAmt = 0;
        scwin.spplyAmtFcrc = 0;
        scwin.bilgAmt = 0;
        scwin.bilgAmtFcrc = 0;
        scwin.fcrcBilgAmt = 0;
        for (var i = 0; i < ds_commonList.getRowCount(); i++) {
            if (ds_commonList.getCellData(i, "choice") == "T") {
                scwin.spplyAmt = scwin.spplyAmt + Number(ds_commonList.getCellData(i, "spplyAmt"));
                scwin.vatAmt = scwin.vatAmt + Number(ds_commonList.getCellData(i, "vatAmt"));
                scwin.spplyAmtFcrc = scwin.spplyAmtFcrc + Number(ds_commonList.getCellData(i, "spplyAmtFcrc"));

                scwin.bilgAmt = scwin.bilgAmt + Number(ds_commonList.getCellData(i, "bilgAmt"));
                scwin.bilgAmtFcrc = scwin.bilgAmtFcrc + Number(ds_commonList.getCellData(i, "bilgAmtFcrc"));
                scwin.fcrcBilgAmt = scwin.fcrcBilgAmt + Number(ds_commonList.getCellData(i, "fcrcBilgAmt"));
            }
        }

        ed_spplyAmt.setValue(scwin.spplyAmt);
        ed_vatAmt.setValue(scwin.vatAmt);
        ed_sumAmt.setValue(Number(scwin.spplyAmt) + Number(scwin.vatAmt));
        ed_spplyAmtFcrc.setValue(scwin.spplyAmtFcrc);

        ds_sellingEvidence.setCellData(0, "bilgAmtFcrc", scwin.bilgAmtFcrc);
        ds_sellingEvidence.setCellData(0, "fcrcBilgAmt", scwin.fcrcBilgAmt);
        ds_sellingEvidence.setCellData(0, "bilgAmt", scwin.bilgAmt);
    }
};


